import { NavLink, Outlet } from 'react-router-dom'

function Products()
{
    return(
        <div>
            <h1>Products</h1>

            //navigation links
            <nav>
                <NavLink to="/products/electronics">Electronics</NavLink>
                <NavLink to="/products/clothing">Clothing</NavLink>
                <NavLink to="/products/furniture">Furniture</NavLink>
            </nav>

            <hr />

            <Outlet />

        </div>
    )
}

export default Products

{/*
        THIS IS THE KEY PART!
        The child route's component renders right here.
        When URL is /products/electronics → <Electronics /> appears here.
        When URL is /products/clothing   → <Clothing /> appears here.
        The rest of the Products page stays unchanged!
      */}